	@echo "Variables:"
	@echo "  VERSION     - Version string (default: git describe)"
	@echo "  COMMIT      - Commit hash (default: git rev-parse)"
	@echo "  DATE        - Build date (default: current UTC time)"
	@echo "  ARGS        - Arguments to pass to 'run' target"

