 84	func TestFixtures(t *testing.T) {
 85		const root = "testdata/fixtures"
 86		cases := listFixtureCases(t, root)
 87		if len(cases) == 0 {
 88			t.Fatal("expected at least one docprose fixture case")
 89		}
 90	
 91		seenModes := map[string]bool{}
 92		for _, tc := range cases {
 93			t.Run(tc.Mode+"/"+tc.Name, func(t *testing.T) {
 94				seenModes[tc.Mode] = true
 95				if strings.TrimSpace(tc.Input) == "" {
 96					t.Fatalf("fixture input is empty")
 97				}
 98				if !strings.Contains(tc.Input, "\n") {
 99					t.Fatalf("fixture input must be markdown with multiple lines")
100				}
101				if !strings.HasSuffix(tc.Golden, "]") {
102					t.Fatalf("golden must be a JSON array: %s", tc.Golden)
103				}
104	
105				got, err := json.MarshalIndent(tc.Findings, "", "  ")
106				if err != nil {
107					t.Fatalf("marshal findings: %v", err)
108				}
109				if strings.TrimSpace(string(got)) != tc.Golden {
110					t.Fatalf("fixture golden mismatch for %s/%s\n--- got ---\n%s\n--- want ---\n%s", tc.Mode, tc.Name, got, tc.Golden)
111				}
112	
113				for i, finding := range tc.Findings {
114					if finding.File == "" || finding.Line == 0 || finding.RuleID == "" || finding.Severity == "" || finding.Rationale == "" || finding.SuggestedEdit == "" {
115						t.Fatalf("finding %d missing required field: %+v", i, finding)
116					}
117				}
118			})
119		}
120	
121		for _, mode := range []string{"technical", "planning", "public"} {
122			if !seenModes[mode] {
123				t.Fatalf("expected at least one fixture in %q mode", mode)
124			}
125		}
126	}
